#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int data;
    struct Node *left, *right;
} Node;

Node* newNode(int data) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->data = data;
    n->left = n->right = NULL;
    return n;
}

int hasPathSum(Node* root, int sum) {
    if (!root) return 0;
    if (!root->left && !root->right) return root->data == sum;
    return hasPathSum(root->left, sum - root->data) || hasPathSum(root->right, sum - root->data);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int *vals = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &vals[i]);
        // consume the third line (may contain spaces and 'N')
        char buf[10005];
        scanf(" %99[^
]", buf); // read until newline, ignore content
        // build tree assuming complete binary order
        Node **nodes = (Node**)calloc(N, sizeof(Node*));
        nodes[0] = newNode(vals[0]);
        for (int i = 0; i < N; ++i) {
            if (!nodes[i]) continue;
            int l = 2*i + 1, r = 2*i + 2;
            if (l < N && vals[l] != -1) {
                nodes[i]->left = newNode(vals[l]);
                nodes[l] = nodes[i]->left;
            }
            if (r < N && vals[r] != -1) {
                nodes[i]->right = newNode(vals[r]);
                nodes[r] = nodes[i]->right;
            }
        }
        printf("%d\n", hasPathSum(nodes[0], K));
        // free memory (omitted for brevity)
        free(vals);
        free(nodes);
    }
    return 0;
}

