import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int data;
        Node left, right;
        Node(int d) { data = d; }
    }

    static boolean hasPathSum(Node root, int sum) {
        if (root == null) return false;
        if (root.left == null && root.right == null) return root.data == sum;
        return hasPathSum(root.left, sum - root.data) || hasPathSum(root.right, sum - root.data);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            int[] vals = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; ++i) vals[i] = Integer.parseInt(st.nextToken());
            br.readLine(); // third line – ignored
            Node[] nodes = new Node[N];
            nodes[0] = new Node(vals[0]);
            for (int i = 0; i < N; ++i) {
                if (nodes[i] == null) continue;
                int l = 2*i + 1, r = 2*i + 2;
                if (l < N && vals[l] != -1) {
                    nodes[i].left = nodes[l] = new Node(vals[l]);
                }
                if (r < N && vals[r] != -1) {
                    nodes[i].right = nodes[r] = new Node(vals[r]);
                }
            }
            System.out.println(hasPathSum(nodes[0], K) ? 1 : 0);
