import sys

def hasPathSum(node, target):
    if node is None:
        return False
    if node.left is None and node.right is None:
        return node.data == target
    return hasPathSum(node.left, target - node.data) or hasPathSum(node.right, target - node.data)

class Node:
    __slots__ = ('data', 'left', 'right')
    def __init__(self, data):
        self.data = data
        self.left = None
        self.right = None

def build_tree(vals):
    n = len(vals)
    nodes = [None] * n
    nodes[0] = Node(vals[0])
    for i in range(n):
        if nodes[i] is None:
            continue
        l = 2*i + 1
        r = 2*i + 2
        if l < n and vals[l] != -1:
            nodes[i].left = nodes[l] = Node(vals[l])
        if r < n and vals[r] != -1:
            nodes[i].right = nodes[r] = Node(vals[r])
    return nodes[0]

def solve():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(t):
        N, K = map(int, data[idx].split()); idx += 1
        vals = list(map(int, data[idx].split())); idx += 1
        idx += 1  # skip third line
        root = build_tree(vals)
        out.append('1' if hasPathSum(root, K) else '0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

